   start_datetime, end_datetime, event_status, visibility_status, parking_info, admission_info)
select
  v.name,
  v.description,
  v.organizer_name,
  v.address,
  v.city,
  v.state,
  v.latitude,
  v.longitude,
  v.start_datetime::timestamptz,
  v.end_datetime::timestamptz,
  v.event_status,
  v.visibility_status,
  v.parking_info,
  v.admission_info
